import { MakeLogicType, actions, afterMount, connect, kea, listeners, path, reducers } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import { teamLogic } from 'scenes/teamLogic'

import {
    logsMetricRulesDestroy,
    logsMetricRulesList,
    logsMetricRulesPartialUpdate,
} from 'products/logs/frontend/generated/api'
import { LogsMetricRuleApi } from 'products/logs/frontend/generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsMetricRulesSectionLogicValues {
    currentTeamId: number | null // teamLogic
    editingRule: LogsMetricRuleApi | null
    ruleModalOpen: boolean
    rules: LogsMetricRuleApi[]
    rulesLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsMetricRulesSectionLogicActions {
    closeRuleModal: () => {
        value: true
    }
    deleteRule: (rule: LogsMetricRuleApi) => {
        rule: LogsMetricRuleApi
    }
    loadRules: () => any
    loadRulesFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadRulesSuccess: (
        rules: LogsMetricRuleApi[],
        payload?: any
    ) => {
        rules: LogsMetricRuleApi[]
        payload?: any
    }
    openEditRuleModal: (rule: LogsMetricRuleApi) => {
        rule: LogsMetricRuleApi
    }
    openNewRuleModal: () => {
        value: true
    }
    setRuleEnabled: (
        rule: LogsMetricRuleApi,
        enabled: boolean
    ) => {
        enabled: boolean
        rule: LogsMetricRuleApi
    }
}

export type logsMetricRulesSectionLogicType = MakeLogicType<
    logsMetricRulesSectionLogicValues,
    logsMetricRulesSectionLogicActions
>

export const logsMetricRulesSectionLogic = kea<logsMetricRulesSectionLogicType>([
    path(['products', 'logs', 'frontend', 'components', 'LogsMetricRules', 'logsMetricRulesSectionLogic']),

    connect(() => ({
        values: [teamLogic, ['currentTeamId']],
    })),

    actions({
        openNewRuleModal: true,
        openEditRuleModal: (rule: LogsMetricRuleApi) => ({ rule }),
        closeRuleModal: true,
        deleteRule: (rule: LogsMetricRuleApi) => ({ rule }),
        setRuleEnabled: (rule: LogsMetricRuleApi, enabled: boolean) => ({ rule, enabled }),
    }),

    loaders(({ values }) => ({
        rules: [
            [] as LogsMetricRuleApi[],
            {
                loadRules: async () => {
                    const response = await logsMetricRulesList(String(values.currentTeamId))
                    return response.results
                },
            },
        ],
    })),

    reducers({
        ruleModalOpen: [
            false,
            {
                openNewRuleModal: () => true,
                openEditRuleModal: () => true,
                closeRuleModal: () => false,
            },
        ],
        editingRule: [
            null as LogsMetricRuleApi | null,
            {
                openNewRuleModal: () => null,
                openEditRuleModal: (_, { rule }) => rule,
                closeRuleModal: () => null,
            },
        ],
    }),

    listeners(({ actions, values }) => ({
        deleteRule: async ({ rule }) => {
            try {
                await logsMetricRulesDestroy(String(values.currentTeamId), rule.id)
                lemonToast.success('Metric rule deleted')
            } catch (e: any) {
                lemonToast.error(e?.detail ?? 'Failed to delete metric rule')
            }
            actions.loadRules()
        },
        setRuleEnabled: async ({ rule, enabled }) => {
            try {
                await logsMetricRulesPartialUpdate(String(values.currentTeamId), rule.id, { enabled })
            } catch (e: any) {
                lemonToast.error(e?.detail ?? 'Failed to update metric rule')
            }
            actions.loadRules()
        },
    })),

    afterMount(({ actions }) => {
        actions.loadRules()
    }),
])
